const res = ($input.first().json.results) || [];
const lines = res.map(p => {
  const pr = p.properties || {};
  const title = ((pr.post||{}).title||[]).map(t=>t.plain_text).join('');
  const views = ((pr.views||{}).number)||0;
  return title ? `- [${views.toLocaleString('ru-RU')} просм.] ${title}` : null;
}).filter(Boolean);
return [{ json: { signals_text: lines.join('\n') || '(нет данных конкурентов)' } }];

const raw = $input.first().json.candidates[0].content.parts[0].text;
const clean = raw.trim().replace(/^```json/i,'').replace(/^```/,'').replace(/```$/,'').trim();
let ideas = JSON.parse(clean);
if (!Array.isArray(ideas)) ideas = ideas.ideas || [ideas];
const max = $('Config').first().json.max_items || 6;
ideas = ideas.slice(0, max);
const hash = s => { s=(s||'').toLowerCase().replace(/[^0-9a-zа-яё ]/gi,'').replace(/\s+/g,' ').trim(); let h=5381; for(let i=0;i<s.length;i++){ h=(((h<<5)+h)+s.charCodeAt(i))&0xffffffff; } return 'h'+(h>>>0).toString(16); };
const now = new Date().toISOString();
const rt = v => ({ rich_text:[{ text:{ content:String(v==null?'':v).slice(0,1900) } }] });
const sel = v => (v && String(v).trim()) ? ({ select:{ name:String(v).split('|')[0].split(',')[0].trim().slice(0,90) } }) : null;
const out = [];
for (const it of ideas) {
  const props = {
    'topic': { title:[{ text:{ content:String(it.topic||'без темы').slice(0,1900) } }] },
    'status': { select:{ name:'Researched' } },
    'content_angle': rt(it.content_angle),
    'summary': rt(it.summary),
    'why_now': rt(it.why_now),
    'source_name': rt(it.source_name),
    'topic_hash': rt(hash(it.topic)),
    'duplicate_status': { select:{ name:'unchecked' } },
    'created_at': { date:{ start: now } },
    'updated_at': { date:{ start: now } }
  };
  const seg = sel(it.audience_segment); if (seg) props['audience_segment']=seg;
  const fc = sel(it.food_category); if (fc) props['food_category']=fc;
  const pt = sel(it.platform_target); if (pt) props['platform_target']=pt;
  if (it.source_url && /^https?:\/\//.test(it.source_url)) props['source_url']={ url: String(it.source_url).slice(0,1900) };
  out.push({ json: { topic: it.topic, notion_props: props } });
}
return out;
